"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["985720"],{964349(a){a.exports=JSON.parse('{"tag":{"label":"lavaarena","permalink":"/dst-api-webdocs/docs/tags/lavaarena","allTagsPath":"/dst-api-webdocs/docs/tags","count":21,"items":[{"id":"game-scripts/prefabs/armor_lavaarena","title":"Armor Lavaarena","description":"Defines and registers multiple armor prefabs for the Lava Arena event with specific builds, tags, and footstep sounds.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/armor_lavaarena"},{"id":"game-scripts/prefabs/blowdart_lava","title":"Blowdart Lava","description":"A specialized blowdart item that launches explosive lava projectiles, using AOE targeting with custom reticule behavior and visual trails.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/blowdart_lava"},{"id":"game-scripts/prefabs/books_lavaarena","title":"Books Lavaarena","description":"Creates and configures the Lava Arena-specific spell books (fossil and elemental) with AOE targeting, reticule visuals, and associated prefabs.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/books_lavaarena"},{"id":"game-scripts/prefabs/fireball_projectile","title":"Fireball Projectile","description":"Creates and configures projectile prefabs and their impact effects for Lava Arena gameplay, including visual tails and hit fx.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/fireball_projectile"},{"id":"game-scripts/prefabs/hammer_mjolnir","title":"Hammer Mjolnir","description":"Defines the Hammer Mjolnir weapon prefab and associated FX prefabs for the Lava Arena event, including reticule targeting and area-of-effect capabilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hammer_mjolnir"},{"id":"game-scripts/prefabs/hats_lavaarena","title":"Hats Lavaarena","description":"Defines and registers lava arena-specific hat prefabs, each initialized with shared animation, physics, and network setup, then delegated to a master-only post-initialization function for gameplay logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hats_lavaarena"},{"id":"game-scripts/prefabs/lavaarena_abigail_flower","title":"Lavaarena Abigail Flower","description":"A non-interactive visual prop used exclusively during the Lava Arena event to represent Abigail\'s presence.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_abigail_flower"},{"id":"game-scripts/prefabs/lavaarena_beetletaur","title":"Lavaarena Beetletaur","description":"Manages client-side visual effects and camera focus for the Lava Arena Beetletaur boss entity, including buff-indicator pulses, break FX, and flower-spawning logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_beetletaur"},{"id":"game-scripts/prefabs/lavaarena_blooms","title":"Lavaarena Blooms","description":"Defines and registers the prefabs for Lava Arena healing flower visual effects, including bloom variations, a heal buff entity, and a sleep debuff entity used during the Lava Arena event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_blooms"},{"id":"game-scripts/prefabs/lavaarena_boaron","title":"Lavaarena Boaron","description":"A hostile minion entity used in the Lava Arena event, registered with the LavaArenaMobTracker for lifecycle monitoring.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_boaron"},{"id":"game-scripts/widgets/redux/lavaarena_communityhistory_panel","title":"Lavaarena Communityhistory Panel","description":"Displays community unlock progression for the Lava Arena event, showing unlock status of bosses, items, and creatures based on server-wide progress.","permalink":"/dst-api-webdocs/docs/game-scripts/widgets/redux/lavaarena_communityhistory_panel"},{"id":"game-scripts/prefabs/lavaarena_creature_spawn_fx","title":"Lavaarena Creature Spawn Fx","description":"Creates visual and audio effects for lava arena creature spawning, including teleport smoke and spark particles, with instance-limited audio volume scaling and server/client separation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_creature_spawn_fx"},{"id":"game-scripts/prefabs/lavaarena_eventstages","title":"Lavaarena Eventstages","description":"Generates prefabs for lava arena event stage triggers used in the Don\'t Starve Together Lava Arena event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_eventstages"},{"id":"game-scripts/prefabs/lavaarena_fossilizing","title":"Lavaarena Fossilizing","description":"Generates and manages network-synchronized debris entities used for visual effects during the Lava Arena event\'s fossilizing effect.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_fossilizing"},{"id":"game-scripts/prefabs/lavaarena_meteor","title":"Lavaarena Meteor","description":"A visual FX prefab for the meteor impact effect in the Lava Arena event, responsible for rendering and initializing the primary meteor projectile and its associated splash sub-effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_meteor"},{"id":"game-scripts/prefabs/lavaarena_rhinodrill","title":"Lavaarena Rhinodrill","description":"Prefab factory for the Lava Arena rhinodrill mob, managing visual state, buff levels, and camera focus tracking via networked properties and world components.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_rhinodrill"},{"id":"game-scripts/components/lavaarenamusic","title":"Lavaarenamusic","description":"Manages background music playback for the Lava Arena event based on the currently activated player and level state.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lavaarenamusic"},{"id":"game-scripts/components/lunarsupernovablocker","title":"Lunarsupernovablocker","description":"Manages visual and gameplay effects for the Lunar Supernova ability by tracking blocking sources and updating related FX and colour properties.","permalink":"/dst-api-webdocs/docs/game-scripts/components/lunarsupernovablocker"},{"id":"game-scripts/prefabs/spear_gungnir","title":"Spear Gungnir","description":"A specialized ranged weapon prefabs with reticule-based targeting, designed for the Lava Arena event, featuring lunge-based attacks and visual effects integration.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spear_gungnir"},{"id":"game-scripts/prefabs/spellmasterybuff","title":"Spellmasterybuff","description":"Creates and manages FX visual prefabs for the Spell Mastery mechanic in the Lava Arena event, including anchor, orb, and orb container entities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/spellmasterybuff"},{"id":"game-scripts/prefabs/wathgrithr_bloodlustbuff","title":"Wathgrithr Bloodlustbuff","description":"A visual effect prefab that appears during Wathgrithr\'s bloodlust mechanic in the Lava Arena event, providing distinct visual feedback for self and other targets.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wathgrithr_bloodlustbuff"}],"unlisted":false}}')}}]);